/**
 * @summary Get public AM profile (requires NIK verification)
 */
export const getGetPublicAmProfileUrl = (
  slug: string,
  params: GetPublicAmProfileParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/public/am/${slug}?${stringifiedParams}`
    : `/api/public/am/${slug}`;
};

export const getPublicAmProfile = async (
  slug: string,
  params: GetPublicAmProfileParams,
  options?: RequestInit,
): Promise<PublicAmProfile> => {
  return customFetch<PublicAmProfile>(getGetPublicAmProfileUrl(slug, params), {
    ...options,
    method: "GET",
  });
};

export const getGetPublicAmProfileQueryKey = (
  slug: string,
  params?: GetPublicAmProfileParams,
) => {
  return [`/api/public/am/${slug}`, ...(params ? [params] : [])] as const;
};

export const getGetPublicAmProfileQueryOptions = <
  TData = Awaited<ReturnType<typeof getPublicAmProfile>>,
  TError = ErrorType<ErrorResponse>,
>(
  slug: string,
  params: GetPublicAmProfileParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getPublicAmProfile>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetPublicAmProfileQueryKey(slug, params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getPublicAmProfile>>
  > = ({ signal }) =>
    getPublicAmProfile(slug, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!slug,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getPublicAmProfile>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetPublicAmProfileQueryResult = NonNullable<
  Awaited<ReturnType<typeof getPublicAmProfile>>
>;
export type GetPublicAmProfileQueryError = ErrorType<ErrorResponse>;

/**
 * @summary Get public AM profile (requires NIK verification)
 */

export function useGetPublicAmProfile<
  TData = Awaited<ReturnType<typeof getPublicAmProfile>>,
  TError = ErrorType<ErrorResponse>,
>(
  slug: string,
  params: GetPublicAmProfileParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getPublicAmProfile>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetPublicAmProfileQueryOptions(slug, params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
